query:
SELECT COUNT(*) as total_mappings FROM mappings;
SELECT m.id, m.ploId, m.competencyId, m.weight, c.code as compCode, c.gaId 
FROM mappings m 
JOIN competencies c ON m.competencyId = c.id 
WHERE m.weight > 0 
LIMIT 10;

